import sys

def solve():
    n = int(sys.stdin.readline())
    a = list(map(int, sys.stdin.readline().split()))

    max_xor = 1 << 9  # Since a_i <= 500, max possible XOR is 512-1
    dp = [float('inf')] * max_xor
    dp[0] = -1  # empty subsequence

    for num in a:
        for x in range(max_xor):
            if dp[x] < num:
                new_x = x ^ num
                if num < dp[new_x]:
                    dp[new_x] = num

    res = []
    for x in range(max_xor):
        if dp[x] != float('inf'):
            res.append(x)
    res.sort()

    print(len(res))
    print(' '.join(map(str, res)))

solve()
